tool.validation_logic:
def track_phase_performance(email_metrics): """ Tracks actual performance per phase after launch.
Use post-launch to identify: - Which phases performed best/worst - Which emails to optimize for next launch - Proof of launch effectiveness
Returns: dict: { 'phase_performance': dict, 'top_performers': list, 'underperformers': list, 'optimization_targets': list, 'overall_conversion_rate': float } """ from collections import defaultdict
# Group metrics by phase phase_data = defaultdict(list)
for metric in email_metrics: phase = metric.get('phase', 'unknown') phase_data[phase].append(metric)
# Calculate average metrics per phase phase_performance = {}
for phase, metrics in phase_data.items(): avg_open_rate = sum(m.get('open_rate', 0) for m in metrics) / len(metrics) avg_click_rate = sum(m.get('click_rate', 0) for m in metrics) / len(metrics) total_conversions = sum(m.get('conversions', 0) for m in metrics)
phase_performance[phase] = { 'avg_open_rate': round(avg_open_rate, 2), 'avg_click_rate': round(avg_click_rate, 2), 'total_conversions': total_conversions, 'email_count': len(metrics) }
# Identify top performers (top 20% by open rate) sorted_by_open = sorted(email_metrics, key=lambda x: x.get('open_rate', 0), reverse=True) top_count = max(1, len(email_metrics) // 5) top_performers = [m.get('email_id') for m in sorted_by_open[:top_count]]
# Identify underperformers (bottom 20% by open rate) underperformers = [m.get('email_id') for m in sorted_by_open[-top_count:]]
# Calculate overall conversion rate total_conversions = sum(m.get('conversions', 0) for m in email_metrics) total_sent = sum(m.get('sent', 0) for m in email_metrics) if email_metrics and 'sent' in email_metrics[0] else 0 overall_conversion_rate = (total_conversions / total_sent * 100) if total_sent > 0 else 0
# Identify optimization targets optimization_targets = []
# Check for weak phases for phase, perf in phase_performance.items(): if perf['avg_open_rate'] < 20: optimization_targets.append(f'{phase}: Low open rate ({perf["avg_open_rate"]}%) - strengthen subject lines') if perf['avg_click_rate'] < 2: optimization_targets.append(f'{phase}: Low click rate ({perf["avg_click_rate"]}%) - improve CTAs')
# Check for conversion concentration if phase_performance.get('close_cart', {}).get('total_conversions', 0) > total_conversions * 0.6: optimization_targets.append('Heavy close_cart conversion concentration - consider strengthening cart_open phase')
result = { 'phase_performance': phase_performance, 'top_performers': top_performers, 'underperformers': underperformers, 'optimization_targets': optimization_targets, 'overall_conversion_rate': round(overall_conversion_rate, 2) }
return result
